const AdminInquiries = () => {
  return (
    <section className="container mx-auto px-4 py-12">
      <h1 className="section-title">Contact Inquiries</h1>
      <p className="section-subtitle">Respond to client inquiries and follow up on leads from the contact form.</p>
      <div className="card p-8 mt-8">
        <p className="text-gray-600">All submitted contact messages are available through the backend contact inquiry API.</p>
      </div>
    </section>
  );
};

export default AdminInquiries;
